    #[test]
    fn test_rust_function_chunks() {
        let source = "fn hello() {\n    println!(\"hello\");\n}\n\nfn world() {\n    println!(\"world\");\n}\n";
        let chunker = AstChunker::new();
        let chunks = chunker.chunk(source, &rust_meta()).unwrap();
        assert_eq!(chunks.len(), 2);
        assert!(chunks[0].content.contains("hello"));
        assert!(chunks[1].content.contains("world"));
        assert_eq!(chunks[0].chunk_type, "function_item");
    }

    #[test]
    fn test_python_class_chunks() {
        let source = "class MyClass:\n    def method(self):\n        pass\n\ndef standalone():\n    return 42\n";
        let chunker = AstChunker::new();
        let chunks = chunker.chunk(source, &py_meta()).unwrap();
        assert!(chunks.len() >= 2);
    }

